args.TargetContent:
:: Kill existing processes on ports 20128, 443, and 1455 first
echo [1/4] Cleaning up any active processes on ports 20128, 443, 1455...
powershell -NoProfile -Command "$ports = @(20128, 443, 1455); foreach ($port in $ports) { $conns = Get-NetTCPConnection -LocalPort $port -ErrorAction SilentlyContinue; foreach ($c in $conns) { if ($c.OwningProcess) { echo \"      Found process PID $($c.OwningProcess) on port $port. Terminating...\"; Stop-Process -Id $c.OwningProcess -Force -ErrorAction SilentlyContinue } } }"
for %%p in (20128 443 1455) do (
    for /f "tokens=5" %%a in ('netstat -aon ^| findstr ":%%p" 2^>nul') do (
        echo       Double-checking: Terminating PID %%a listening on port %%p...
        taskkill /F /PID %%a >nul 2>&1
    )
)

:: When Electron closes, stop the server
echo.
echo Shutting down server...
for %%p in (20128 443 1455) do (
    for /f "tokens=5" %%a in ('netstat -aon ^| findstr ":%%p" ^| findstr "LISTENING" 2^>nul') do (
        taskkill /F /PID %%a >nul 2>&1
    )
)
echo Done. Goodbye!
